import type {
  PriventClientOptions,
  VaultFactory,
  Tokenizer,
  RiskScorer,
  AuditLogger,
  TokenVault,
  Logger,
  AgentHandoffOptions,
} from './interfaces.js';
import { HttpClient } from './http.js';
import { CloudVaultFactory, InMemoryVaultFactory } from './vault/index.js';
import { HybridTokenizer } from './tokenizer/index.js';
import { CloudRiskScorer } from './cloud/risk-scorer.js';
import { CloudAuditLogger } from './cloud/audit-logger.js';
import {
  MissingCredentialsRiskScorer,
  MissingCredentialsAuditLogger,
} from './cloud/missing-credentials.js';

declare const __SDK_VERSION__: string;

export class PriventClient {
  readonly vaultFactory: VaultFactory;
  readonly tokenizer: Tokenizer;
  readonly riskScorer: RiskScorer;
  readonly auditLogger: AuditLogger;
  /** `open` = allow workflow to continue when cloud is unreachable. Default: `open`. */
  readonly failPolicy: 'open' | 'closed';
  /** Internal HTTP client. Present only when an apiKey was provided. */
  readonly _http: HttpClient | undefined;

  private readonly _logger: Logger | undefined;

  constructor(opts: PriventClientOptions = {}) {
    const apiKey = opts.apiKey ?? process.env['PRIVENT_API_KEY'];
    const baseUrl =
      opts.baseUrl ??
      process.env['PRIVENT_BASE_URL'] ??
      'https://api.privent.ai';

    // Default timeout bumped 30s → 120s to accommodate the NuExtract path on
    // ml.privent.ai (two-pass extraction on L4 + enforce_eager runs ~46-95s
    // end-to-end). At 30s the SDK would abort + fail-open with model='fallback'
    // before the backend's own 120s ML window had a chance to complete.
    const http =
      apiKey != null
        ? new HttpClient({
            baseUrl,
            apiKey,
            maxRetries: opts.maxRetries ?? 2,
            timeoutMs: opts.timeout ?? 120_000,
          })
        : undefined;

    // Dedicated client for the privent-ml service (NuExtract + validators).
    // Production default is `https://ml.privent.ai`; override via
    // `PRIVENT_ML_URL` (or the `mlBaseUrl` option) for local Docker dev.
    //
    // The ML client is constructed ONLY when an explicit `mlSharedSecret`
    // (or `PRIVENT_ML_SHARED_SECRET` env) is configured. ml.privent.ai uses
    // a different shared secret than the Privent Cloud `apiKey`, so falling
    // back to the Cloud key would 401 silently and the tokenizer would
    // fail-open with empty entities. When no ML secret is configured the
    // HybridTokenizer routes its ML enrichment pass through the Cloud
    // backend (`/v1/risk/score`), which holds its own ML secret server-side.
    const mlBaseUrlExplicit = opts.mlBaseUrl ?? process.env['PRIVENT_ML_URL'];
    const mlBaseUrl = mlBaseUrlExplicit ?? 'https://ml.privent.ai';
    const mlSharedSecret =
      opts.mlSharedSecret ?? process.env['PRIVENT_ML_SHARED_SECRET'];
    const mlHttp =
      mlSharedSecret != null && mlSharedSecret !== ''
        ? new HttpClient({
            baseUrl: mlBaseUrl,
            apiKey: mlSharedSecret,
            maxRetries: opts.maxRetries ?? 2,
            timeoutMs: opts.timeout ?? 120_000,
          })
        : undefined;

    // Cloud vault requires the HTTP client (Authorization, retries, CB). When
    // an operator selects `cloud` without an apiKey, fall back to in-memory
    // rather than crashing at construction — the missing-credentials sentinels
    // surface the misconfiguration on the first cloud-dependent call.
    this.vaultFactory =
      opts.vaultFactory ??
      (opts.vaultBackend === 'cloud' && http
        ? new CloudVaultFactory(http)
        : new InMemoryVaultFactory());
    this.tokenizer = opts.tokenizer ?? new HybridTokenizer(undefined, http, mlHttp);
    // When no apiKey is configured, install missing-credentials sentinels
    // instead of silent no-ops.  Tokenization keeps working (local regex);
    // any cloud-dependent call surfaces PRIVENT_CREDENTIALS_MISSING_MESSAGE
    // so misconfigurations fail loud at the call site.
    this.riskScorer =
      opts.riskScorer ?? (http ? new CloudRiskScorer(http) : new MissingCredentialsRiskScorer());
    this.auditLogger =
      opts.auditLogger ?? (http ? new CloudAuditLogger(http) : new MissingCredentialsAuditLogger());
    this.failPolicy = opts.failPolicy ?? 'open';
    this._http = http;
    this._logger = opts.logger;
  }

  /**
   * Emit a Trust Map `agent_handoff` audit event. Use this whenever an agent
   * delegates work to another agent (subgraph call, supervisor → worker,
   * webhook trigger of a downstream workflow). Backend's trust-map aggregator
   * upserts an `AgentInteraction` edge from the resulting event.
   *
   * Either `toAgentName`/`toAgentId` OR `toSinkId` should be set — backend
   * enforces the XOR constraint. Leave all three null when the target is
   * unknown at emit time; the resolver service will attempt to fill
   * `targetAgentId` post-ingest from the `InternalAgentEndpoint` registry.
   */
  async handoff(opts: AgentHandoffOptions): Promise<void> {
    await this.auditLogger.log({
      type: 'agent_handoff',
      traceId: opts.traceId,
      sessionId: opts.sessionId,
      timestamp: opts.timestamp ?? Date.now(),
      framework: opts.framework,
      metadata: opts.metadata ?? {},
      ...(opts.workflowId != null ? { workflowId: opts.workflowId } : {}),
      ...(opts.nodeId != null ? { nodeId: opts.nodeId } : {}),
      ...(opts.nodeName != null ? { nodeName: opts.nodeName } : {}),
      fromAgentName: opts.fromAgentName,
      ...(opts.fromAgentId != null ? { fromAgentId: opts.fromAgentId } : {}),
      ...(opts.toAgentName != null ? { targetAgentName: opts.toAgentName } : {}),
      ...(opts.toAgentId != null ? { targetAgentId: opts.toAgentId } : {}),
      ...(opts.toSinkId != null ? { targetSinkId: opts.toSinkId } : {}),
      reason: opts.reason,
      ...(opts.payloadTokenCount != null
        ? { payloadTokenCount: opts.payloadTokenCount }
        : {}),
      ...(opts.riskLevel != null ? { riskLevel: opts.riskLevel } : {}),
      ...(opts.parentEventId != null
        ? { parentEventId: opts.parentEventId }
        : {}),
      ...(opts.branchId != null ? { branchId: opts.branchId } : {}),
      ...(opts.hopDepth != null ? { hopDepth: opts.hopDepth } : {}),
    });
  }

  /**
   * Opens a session vault, runs `fn`, then destroys the vault in a `finally` block.
   * The traceId is a correlation ID that should be forwarded to all downstream operations.
   */
  async withSession<T>(
    fn: (ctx: { vault: TokenVault; traceId: string; sessionId: string }) => Promise<T>,
  ): Promise<T> {
    const sessionId = crypto.randomUUID();
    const traceId = crypto.randomUUID();
    const vault = this.vaultFactory.create(sessionId);

    this._logger?.debug('privent: session opened', {
      sessionId,
      traceId,
      sdkVersion: __SDK_VERSION__,
    });

    try {
      return await fn({ vault, traceId, sessionId });
    } finally {
      await vault.destroy();
      this._logger?.debug('privent: session closed', { sessionId, traceId });
    }
  }
}
