import type { RiskScorer } from '../interfaces.js';
import type { RiskScore } from '../types.js';
import type { HttpClient } from '../http.js';
import type { EntityItemV1 } from '../contracts/v1/entities.js';
import {
  PriventAuthError,
  PriventBatchLengthMismatchError,
  PriventCircuitOpenError,
  PriventRateLimitError,
} from '../errors.js';

const CACHE_MAX = 500;
const CACHE_TTL_MS = 5 * 60 * 1000;

const FALLBACK: RiskScore = {
  risk_score: 0,
  risk_level: 'LOW',
  categories: {},
  model: 'fallback',
  latencyMs: 0,
  entities: null,
};

async function cacheKey(text: string): Promise<string> {
  const encoded = new TextEncoder().encode(text);
  const buf = await crypto.subtle.digest('SHA-256', encoded);
  return Array.from(new Uint8Array(buf))
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('')
    .slice(0, 16);
}

interface CacheEntry {
  value: RiskScore;
  expiresAt: number;
}

interface CloudScoreResponse {
  risk_score: number;
  risk_level: string;
  categories: Record<string, number>;
  model: string;
  latency_ms: number;
  entities?: EntityItemV1[] | null;
}

interface CloudBatchResponse {
  results: CloudScoreResponse[];
}

function toRiskScore(r: CloudScoreResponse, start: number): RiskScore {
  return {
    risk_score: r.risk_score,
    risk_level: r.risk_level as RiskScore['risk_level'],
    categories: r.categories,
    model: r.model,
    latencyMs: Date.now() - start,
    entities: r.entities ?? null,
  };
}

/**
 * Rethrown errors (not caught by the failopen branch) — these reflect a
 * deliberate failure mode (auth, rate limit, circuit open, contract
 * violation) where falling back to a synthetic LOW score would mask the
 * issue from callers.
 */
function isFatal(err: unknown): boolean {
  return (
    err instanceof PriventAuthError ||
    err instanceof PriventRateLimitError ||
    err instanceof PriventCircuitOpenError ||
    err instanceof PriventBatchLengthMismatchError
  );
}

export class CloudRiskScorer implements RiskScorer {
  /**
   * LRU cache of recent scores. `Map` preserves insertion order in JS, and
   * we re-insert on every read to bump the entry to the most-recent slot.
   */
  private readonly cache = new Map<string, CacheEntry>();

  constructor(private readonly http: HttpClient) {}

  async score(
    input: { text: string; context?: string },
    signal?: AbortSignal,
  ): Promise<RiskScore> {
    const start = Date.now();
    const key = await cacheKey(input.text);
    const cached = this.getCached(key);
    if (cached !== null) return cached;

    try {
      const res = await this.http.request<CloudScoreResponse>('/v1/risk/score', {
        method: 'POST',
        body: { text: input.text, include_entities: true },
        ...(signal != null && { signal }),
      });
      const score = toRiskScore(res, start);
      this.setCache(key, score);
      return score;
    } catch (err) {
      if (isFatal(err)) throw err;
      return { ...FALLBACK, latencyMs: Date.now() - start };
    }
  }

  async scoreBatch(
    inputs: Array<{ text: string }>,
    signal?: AbortSignal,
  ): Promise<RiskScore[]> {
    const start = Date.now();

    const keys = await Promise.all(inputs.map((i) => cacheKey(i.text)));
    const cachedHits = keys.map((k) => this.getCached(k));
    if (cachedHits.every((c) => c !== null)) {
      return cachedHits as RiskScore[];
    }

    try {
      const res = await this.http.request<CloudBatchResponse>('/v1/risk/batch', {
        method: 'POST',
        body: { items: inputs.map((it) => ({ ...it, include_entities: true })) },
        ...(signal != null && { signal }),
      });

      // Backend contract: results.length === items.length, in input order.
      // A mismatch is an upstream bug; we throw rather than guess at indices.
      if (!Array.isArray(res.results) || res.results.length !== inputs.length) {
        throw new PriventBatchLengthMismatchError(
          inputs.length,
          Array.isArray(res.results) ? res.results.length : 0,
        );
      }

      return res.results.map((r, i) => {
        const score = toRiskScore(r, start);
        this.setCache(keys[i]!, score);
        return score;
      });
    } catch (err) {
      if (isFatal(err)) throw err;
      const fallback = { ...FALLBACK, latencyMs: Date.now() - start };
      return inputs.map(() => fallback);
    }
  }

  /** LRU read: returns null on miss/expired; bumps recency on hit. */
  private getCached(key: string): RiskScore | null {
    const entry = this.cache.get(key);
    if (entry == null) return null;
    if (entry.expiresAt <= Date.now()) {
      this.cache.delete(key);
      return null;
    }
    // Refresh recency: delete + re-insert moves to tail.
    this.cache.delete(key);
    this.cache.set(key, entry);
    return entry.value;
  }

  private setCache(key: string, value: RiskScore): void {
    // If the key is already present, delete first so re-insert lands at tail.
    if (this.cache.has(key)) this.cache.delete(key);
    while (this.cache.size >= CACHE_MAX) {
      // Map iteration order is insertion order; oldest-first.
      const oldest = this.cache.keys().next().value;
      if (oldest === undefined) break;
      this.cache.delete(oldest);
    }
    this.cache.set(key, { value, expiresAt: Date.now() + CACHE_TTL_MS });
  }
}
