import type { RiskScorer } from '../interfaces.js';
import type { RiskScore } from '../types.js';

const NOOP_SCORE: RiskScore = {
  risk_score: 0,
  risk_level: 'LOW',
  categories: {},
  model: 'noop',
  latencyMs: 0,
};

/**
 * Week 1 placeholder. Returns a zero-risk score for all inputs.
 * Replaced by CloudRiskScorer (calls privent-ml via Privent Cloud) in Week 3.
 */
export class NoopRiskScorer implements RiskScorer {
  async score(_input: { text: string; context?: string }): Promise<RiskScore> {
    return NOOP_SCORE;
  }

  async scoreBatch(inputs: Array<{ text: string }>): Promise<RiskScore[]> {
    return inputs.map(() => NOOP_SCORE);
  }
}
