export type PriventErrorCode =
  | 'CONFIG_ERROR'
  | 'AUTH_ERROR'
  | 'RATE_LIMIT_ERROR'
  | 'API_ERROR'
  | 'NETWORK_ERROR'
  | 'TIMEOUT_ERROR'
  | 'VALIDATION_ERROR'
  | 'VAULT_FULL'
  | 'VAULT_DESTROYED'
  | 'VAULT_CORRUPTED'
  | 'CIRCUIT_OPEN'
  | 'BATCH_LENGTH_MISMATCH'
  | 'CREDENTIALS_MISSING';

/**
 * Guided message surfaced when a Privent integration tries to invoke a
 * cloud-only feature (risk scoring, audit upload) without an apiKey.
 *
 * Single source of truth — n8n nodes, LangGraph middleware, and CrewAI hooks
 * all reuse this exact text so the wording cannot drift between integrations.
 *
 * Newlines and the bullet `•` (U+2022, with a double space prefix) are part
 * of the contract — keep them intact.
 */
export const PRIVENT_CREDENTIALS_MISSING_MESSAGE =
  'Privent credentials not found.\n' +
  'Get your API key: https://privent.ai/request-access\n' +
  'Early access  • Respond in 24h';

export class PriventError extends Error {
  readonly code: PriventErrorCode;
  readonly retryable: boolean;
  readonly requestId?: string;
  readonly statusCode?: number;

  constructor(
    message: string,
    opts: {
      code: PriventErrorCode;
      retryable: boolean;
      requestId?: string;
      statusCode?: number;
      cause?: unknown;
    },
  ) {
    super(message, opts.cause != null ? { cause: opts.cause } : undefined);
    this.name = 'PriventError';
    this.code = opts.code;
    this.retryable = opts.retryable;
    if (opts.requestId !== undefined) this.requestId = opts.requestId;
    if (opts.statusCode !== undefined) this.statusCode = opts.statusCode;
  }

  toJSON(): Record<string, unknown> {
    return {
      name: this.name,
      message: this.message,
      code: this.code,
      retryable: this.retryable,
      ...(this.requestId !== undefined && { requestId: this.requestId }),
      ...(this.statusCode !== undefined && { statusCode: this.statusCode }),
    };
  }
}

export class PriventConfigError extends PriventError {
  constructor(message: string, opts?: { cause?: unknown }) {
    super(message, { code: 'CONFIG_ERROR', retryable: false, ...(opts ?? {}) });
    this.name = 'PriventConfigError';
  }
}

export class PriventAuthError extends PriventError {
  constructor(message: string, opts?: { statusCode?: number; requestId?: string }) {
    super(message, { code: 'AUTH_ERROR', retryable: false, ...(opts ?? {}) });
    this.name = 'PriventAuthError';
  }
}

export class PriventRateLimitError extends PriventError {
  constructor(message: string, opts?: { statusCode?: number; requestId?: string }) {
    super(message, { code: 'RATE_LIMIT_ERROR', retryable: true, ...(opts ?? {}) });
    this.name = 'PriventRateLimitError';
  }
}

export class PriventAPIError extends PriventError {
  constructor(
    message: string,
    opts?: { statusCode?: number; requestId?: string; retryable?: boolean },
  ) {
    super(message, {
      code: 'API_ERROR',
      retryable: opts?.retryable ?? false,
      ...(opts?.statusCode !== undefined && { statusCode: opts.statusCode }),
      ...(opts?.requestId !== undefined && { requestId: opts.requestId }),
    });
    this.name = 'PriventAPIError';
  }
}

export class PriventNetworkError extends PriventError {
  constructor(message: string, opts?: { requestId?: string; cause?: unknown }) {
    super(message, { code: 'NETWORK_ERROR', retryable: true, ...(opts ?? {}) });
    this.name = 'PriventNetworkError';
  }
}

export class PriventTimeoutError extends PriventError {
  constructor(message: string, opts?: { requestId?: string }) {
    super(message, { code: 'TIMEOUT_ERROR', retryable: true, ...(opts ?? {}) });
    this.name = 'PriventTimeoutError';
  }
}

export class PriventValidationError extends PriventError {
  constructor(message: string, opts?: { cause?: unknown }) {
    super(message, { code: 'VALIDATION_ERROR', retryable: false, ...(opts ?? {}) });
    this.name = 'PriventValidationError';
  }
}

export class PriventVaultFullError extends PriventError {
  constructor(sessionId: string, cap: number) {
    super(`Vault for session ${sessionId} exceeded the ${cap}-entry cap`, {
      code: 'VAULT_FULL',
      retryable: false,
    });
    this.name = 'PriventVaultFullError';
  }
}

export class PriventVaultDestroyedError extends PriventError {
  constructor(sessionId: string) {
    super(`Vault for session ${sessionId} has been destroyed`, {
      code: 'VAULT_DESTROYED',
      retryable: false,
    });
    this.name = 'PriventVaultDestroyedError';
  }
}

/**
 * A vault entry was returned from the cloud backend but could not be
 * decrypted (auth tag mismatch, wrong key, corrupted row). Fail-loud:
 * `retryable=false` so the SDK HTTP layer won't replay the request, and
 * tokenizer/detokenizer callers must let it bubble up instead of silently
 * substituting a placeholder — audit-only positioning still applies.
 */
export class PriventVaultCorruptedError extends PriventError {
  readonly token?: string;

  constructor(opts: { token?: string; requestId?: string; statusCode?: number } = {}) {
    super('Vault entry could not be decrypted', {
      code: 'VAULT_CORRUPTED',
      retryable: false,
      ...(opts.requestId !== undefined && { requestId: opts.requestId }),
      ...(opts.statusCode !== undefined && { statusCode: opts.statusCode }),
    });
    this.name = 'PriventVaultCorruptedError';
    if (opts.token !== undefined) this.token = opts.token;
  }
}

/**
 * Per-host circuit breaker is OPEN; the request was rejected without an
 * upstream call. Surfaces only when failPolicy='closed'; in 'open' mode
 * callers (CloudRiskScorer) catch and fall back to local regex.
 */
export class PriventCircuitOpenError extends PriventError {
  constructor(host: string, opts?: { requestId?: string }) {
    super(`Circuit breaker is OPEN for host ${host}`, {
      code: 'CIRCUIT_OPEN',
      retryable: false,
      ...(opts ?? {}),
    });
    this.name = 'PriventCircuitOpenError';
  }
}

/**
 * Thrown by the missing-credentials sentinel implementations of RiskScorer
 * and AuditLogger when a caller invokes a cloud feature without supplying an
 * apiKey.  Message is always {@link PRIVENT_CREDENTIALS_MISSING_MESSAGE} so
 * every Privent integration surfaces the same guided text.
 */
export class PriventCredentialsError extends PriventError {
  constructor(opts?: { cause?: unknown }) {
    super(PRIVENT_CREDENTIALS_MISSING_MESSAGE, {
      code: 'CREDENTIALS_MISSING',
      retryable: false,
      ...(opts ?? {}),
    });
    this.name = 'PriventCredentialsError';
  }
}

/**
 * Batch endpoint contract violation: response.results.length !==
 * request.items.length. Indicates upstream bug; not retryable since identical
 * input would yield identical (broken) output.
 */
export class PriventBatchLengthMismatchError extends PriventError {
  constructor(expected: number, actual: number, opts?: { requestId?: string }) {
    super(`Batch length mismatch: expected ${expected} results, got ${actual}`, {
      code: 'BATCH_LENGTH_MISMATCH',
      retryable: false,
      statusCode: 502,
      ...(opts ?? {}),
    });
    this.name = 'PriventBatchLengthMismatchError';
  }
}
