import { z } from 'zod';

export const ServiceStatusEnum = z.enum(['ok', 'degraded', 'down']);
export type ServiceStatusV1 = z.infer<typeof ServiceStatusEnum>;

export const CircuitStateEnum = z.enum(['CLOSED', 'OPEN', 'HALF_OPEN']);
export type CircuitStateV1 = z.infer<typeof CircuitStateEnum>;

/**
 * GET /v1/health response. Backend reports its own status plus aggregated
 * downstream signals (privent-ml CB state).
 */
export const HealthResponseSchema = z
  .object({
    status: ServiceStatusEnum,
    version: z.string().min(1),
    uptime_ms: z.number().int().nonnegative(),
    ml_status: CircuitStateEnum.optional(),
  })
  .strict();
export type HealthResponseV1 = z.infer<typeof HealthResponseSchema>;
